const counter = $getWorkflowStaticData('global');

// --- Skip logic: publish 2 out of every 3 days = every 1.5 days ---
let dayCount = counter.dayCount || 0;
dayCount++;
counter.dayCount = dayCount;
if (dayCount % 3 === 0) {
  return [];
}

let index = counter.topicIndex || 0;
if (index >= topics.length) index = 0;

const recentTopics = counter.recentTopics || [];
let attempts = 0;
while (recentTopics.includes(index) && attempts < topics.length) {
  index = (index + 1) % topics.length;
  attempts++;
}
recentTopics.push(index);
if (recentTopics.length > 5) recentTopics.shift();
counter.recentTopics = recentTopics;

const pick = topics[index];
counter.topicIndex = (index + 1) % topics.length;

return [{ json: { topic: pick.topic, keyword: pick.keyword, category: pick.category, img: pick.img, word_count: pick.word_count, current_index: index } }];

const data = $('ارسال به Claude').first().json;
let raw = '';

if (data.content && Array.isArray(data.content)) {
  raw = data.content[0].text;
} else if (data.text) {
  raw = data.text;
} else if (data.error) {
  const errMsg = typeof data.error === 'string' ? data.error : (data.error.message || JSON.stringify(data.error));
  throw new Error('خطای Claude: ' + errMsg);
} else {
  throw new Error('پاسخ نامعتبر - کلیدهای دریافتی: ' + Object.keys(data).join(', '));
}

if (!raw || raw.length < 50) {
  throw new Error('پاسخ خیلی کوتاه یا خالی: ' + raw.substring(0, 200));
}

function getPart(label, next) {
  let s = raw.indexOf('===' + label + '===');
  if (s === -1) return '';
  s += ('===' + label + '===').length;
  let e = next ? raw.indexOf('===' + next + '===') : raw.length;
  if (e === -1) e = raw.length;
  return raw.substring(s, e).trim();
}

const topicData = $('انتخاب موضوع').first().json;

let titleA = getPart('TITLE_A', 'TITLE_B') || topicData.topic;
let titleB = getPart('TITLE_B', 'SLUG') || titleA;

const useA = Math.random() > 0.5;
let title = useA ? titleA : titleB;
let abVariant = useA ? 'A' : 'B';

let slug = getPart('SLUG', 'CONTENT') || '';
let content = getPart('CONTENT', 'FAQ_SCHEMA');
let faqSchema = getPart('FAQ_SCHEMA', 'KEYWORD') || '';
let keyword = getPart('KEYWORD', 'META') || topicData.keyword;
let meta = getPart('META', null) || title;
let category = topicData.category || '';

if (!content) {
  content = raw;
}

if (faqSchema) {
  try {
    JSON.parse(faqSchema);
    content += '\n<script type="application/ld+json">' + faqSchema + '</script>';
  } catch(e) {}
}

return [{ json: { title, titleA, titleB, abVariant, slug, content, focus_keyword: keyword, meta_description: meta, category } }];

const data = $json;
const photos = data.photos || [];
if (photos.length === 0) {
  throw new Error('تصویری پیدا نشد');
}
const seed = Date.now() + Math.random() * 10000;
const pick = photos[Math.floor(seed % photos.length)];
const imageUrl = pick.src.large2x || pick.src.large || pick.src.original;
const photographer = pick.photographer || '';
return [{ json: { imageUrl, photographer } }];

const postId = $json.id;
const parsedData = $('پردازش پاسخ').item.json;
const imageId = $('آپلود تصویر').item.json.id;
const categoryName = parsedData.category;

const body = {
  featured_media: imageId,
  meta: {
    rank_math_focus_keyword: parsedData.focus_keyword,
    rank_math_description: parsedData.meta_description,
    rank_math_title: parsedData.title
  }
};

return [{ json: { postId, body: JSON.stringify(body), categoryName, postUrl: $json.link || ('https://digikord.com/?p=' + postId), title: parsedData.title, abVariant: parsedData.abVariant, titleA: parsedData.titleA, titleB: parsedData.titleB, keyword: parsedData.focus_keyword } }];

const postId = $('آماده‌سازی آپدیت').item.json.postId;
const data = $json;
let categoryId = null;

if (data && data.id) {
  categoryId = data.id;
} else if (Array.isArray(data) && data.length > 0) {
  categoryId = data[0].id;
}

if (!categoryId) {
  return [{ json: { postId, body: '{}' } }];
}

return [{ json: { postId, categoryId, body: JSON.stringify({ categories: [categoryId] }) } }];

const postId = $('آماده‌سازی آپدیت').item.json.postId;
const data = $json;
let tagId = null;

if (data && data.id) {
  tagId = data.id;
} else if (Array.isArray(data) && data.length > 0) {
  tagId = data[0].id;
}

if (!tagId) {
  return [{ json: { postId, body: '{}' } }];
}

return [{ json: { postId, tagId, body: JSON.stringify({ tags: [tagId] }) } }];
